import React from 'react';
import { Button, Input } from '@linm-soft-org/linm-web-common-components';
import { VoucherDocumentFormShell } from './VoucherDocumentFormShell';
import { MaterialLinesGridActions } from './MaterialLinesGridActions';
import { useMaterialLinesSelection } from './useMaterialLinesSelection';
import { LineMaterialSearchCell, MaterialLineTableHeaders } from '../search';
import type { VoucherLineDto } from '../../services/kho/models';
import erp from '../../styles/erpPage.module.css';
import df from '../../styles/documentForm.module.css';

export type InlineVoucherMaterialCreatePanelProps = {
  testId: string;
  headerFields: React.ReactNode;
  lines: VoucherLineDto[];
  setLines: React.Dispatch<React.SetStateAction<VoucherLineDto[]>>;
  updateLine: (idx: number, patch: Partial<VoucherLineDto>) => void;
  emptyLine: () => VoucherLineDto;
  onSave: () => void;
  onClose: () => void;
  saving: boolean;
  canEdit?: boolean;
  showUnitPrice?: boolean;
};

/** Inline list create — GAP-P2-43 shell + GAP-P2-45 copy row (parity full-page voucher). */
export function InlineVoucherMaterialCreatePanel({
  testId,
  headerFields,
  lines,
  setLines,
  updateLine,
  emptyLine,
  onSave,
  onClose,
  saving,
  canEdit = true,
  showUnitPrice = false,
}: InlineVoucherMaterialCreatePanelProps): React.ReactElement {
  const { copyLine, lineRowProps } = useMaterialLinesSelection(lines, setLines);

  const footer = (
    <div className={erp.paginationRow}>
      <Button variant="secondary" onClick={onClose} data-testid={`${testId}-create-close`}>
        Đóng
      </Button>
      <Button
        variant="primary"
        onClick={onSave}
        disabled={saving || !canEdit}
        data-testid={`${testId}-create-save`}
      >
        {saving ? 'Đang lưu...' : 'Lưu'}
      </Button>
    </div>
  );

  return (
    <VoucherDocumentFormShell
      testId={testId}
      variant="inline"
      header={headerFields}
      footer={footer}
    >
      <MaterialLinesGridActions
        canEdit={canEdit}
        onAddLine={() => setLines(p => [...p, emptyLine()])}
        onCopyLine={copyLine}
        linesCount={lines.length}
      />
      <div className={erp.tableWrapper}>
        <table className={erp.table}>
          <thead>
            <tr>
              <MaterialLineTableHeaders />
              <th>ĐVT</th>
              <th className={erp.colRight}>SL</th>
              {showUnitPrice ? <th className={erp.colRight}>ĐG</th> : null}
              <th />
            </tr>
          </thead>
          <tbody>
            {lines.map((line, idx) => (
              <tr key={idx} {...lineRowProps(idx)}>
                <LineMaterialSearchCell
                  materialCode={line.materialCode}
                  materialName={line.materialName ?? ''}
                  onSelect={m =>
                    updateLine(idx, {
                      materialCode: m.code,
                      materialName: m.name,
                      unitCode: m.unitCode ?? line.unitCode,
                    })
                  }
                  onClear={() => updateLine(idx, { materialCode: '', materialName: '' })}
                />
                <td>
                  <Input
                    value={line.unitCode}
                    onChange={e => updateLine(idx, { unitCode: e.target.value })}
                    size="small"
                  />
                </td>
                <td className={erp.colRight}>
                  <Input
                    type="number"
                    value={String(line.quantity)}
                    onChange={e => updateLine(idx, { quantity: Number(e.target.value) })}
                    size="small"
                  />
                </td>
                {showUnitPrice ? (
                  <td className={erp.colRight}>
                    <Input
                      type="number"
                      value={String(line.unitPrice ?? 0)}
                      onChange={e => updateLine(idx, { unitPrice: Number(e.target.value) })}
                      size="small"
                    />
                  </td>
                ) : null}
                <td>
                  <button
                    type="button"
                    className={erp.actionBtn}
                    onClick={() => setLines(p => p.filter((_, i) => i !== idx))}
                    disabled={lines.length <= 1}
                    aria-label="Xóa dòng"
                  >
                    <i className="fas fa-trash" />
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </VoucherDocumentFormShell>
  );
}
